import{_ as a,o as r,c as i,a2 as l}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Report Task Lifecycle","description":"","frontmatter":{},"headers":[],"relativePath":"projects/arti/contracts/report-tasks.md","filePath":"projects/arti/contracts/report-tasks.md"}'),t={name:"projects/arti/contracts/report-tasks.md"};function o(s,e,n,c,p,d){return r(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="report-task-lifecycle" tabindex="-1">Report Task Lifecycle <a class="header-anchor" href="#report-task-lifecycle" aria-label="Permalink to &quot;Report Task Lifecycle&quot;">​</a></h1><p><strong>状态：Current</strong></p><p><strong>核对日期：2026-06-15</strong></p><p><strong>Schema Owner：<code>arti</code></strong></p><p><strong>Runtime Owner：<code>ARTI_backend</code></strong></p><h2 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to &quot;目的&quot;">​</a></h2><p><code>report_tasks</code> 是浏览器、Backend API、Worker、通知和退款机制之间的异步边界。</p><h2 id="状态机" tabindex="-1">状态机 <a class="header-anchor" href="#状态机" aria-label="Permalink to &quot;状态机&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pending</span></span>
<span class="line"><span>  → processing</span></span>
<span class="line"><span>      ├→ done</span></span>
<span class="line"><span>      └→ failed</span></span>
<span class="line"><span></span></span>
<span class="line"><span>processing</span></span>
<span class="line"><span>  → pending    仅恢复或重试流程</span></span></code></pre></div><p>合法终态为 <code>done</code> 和 <code>failed</code>。消费者不得创造新的状态字符串而不先修改 schema 和全部读取方。</p><h2 id="生产者责任" tabindex="-1">生产者责任 <a class="header-anchor" href="#生产者责任" aria-label="Permalink to &quot;生产者责任&quot;">​</a></h2><p>创建任务的服务端入口必须：</p><ol><li>验证用户身份和请求。</li><li>先检查可复用缓存。</li><li>需要计费时，在服务端完成原子扣费。</li><li>创建 <code>report_tasks</code> 行并关联扣费交易。</li><li>将任务可靠放入队列。</li><li>入队失败时标记失败并触发对应退款语义。</li></ol><p>新入口不得绕过服务端，允许浏览器直接伪造任务状态或扣费关联。</p><h2 id="worker-责任" tabindex="-1">Worker 责任 <a class="header-anchor" href="#worker-责任" aria-label="Permalink to &quot;Worker 责任&quot;">​</a></h2><p>Worker 必须：</p><ul><li>消费队列后将任务推进为 <code>processing</code></li><li>对单个 Analyst 失败执行可控降级</li><li>使用 canonical result assembler 写入结果</li><li>成功时写 <code>done</code> 和完成时间</li><li>失败时写 <code>failed</code> 和可诊断错误</li><li>保持任务处理幂等，避免重复副作用</li></ul><p>恢复程序可以把确认失去有效 Job 的僵尸任务从 <code>processing</code> 重置为 <code>pending</code>。重置不是普通业务状态迁移。</p><h2 id="消费者责任" tabindex="-1">消费者责任 <a class="header-anchor" href="#消费者责任" aria-label="Permalink to &quot;消费者责任&quot;">​</a></h2><p>主站可以通过 Realtime、查询或轮询观察任务，但必须：</p><ul><li>把状态作为服务端事实</li><li>对重复事件保持幂等</li><li>不把组件卸载等同于取消任务</li><li>对未知或缺失结果显示可恢复状态</li></ul><h2 id="副作用" tabindex="-1">副作用 <a class="header-anchor" href="#副作用" aria-label="Permalink to &quot;副作用&quot;">​</a></h2><p>任务终态可能触发：</p><ul><li>报告完成或失败通知</li><li>失败退款</li><li>Chat 中的报告就绪卡片</li><li>预测目标价回写</li></ul><p>这些副作用必须有幂等键或唯一约束，不应依赖一次性前端回调。</p><h2 id="修改检查" tabindex="-1">修改检查 <a class="header-anchor" href="#修改检查" aria-label="Permalink to &quot;修改检查&quot;">​</a></h2><ul><li>状态集合是否变化</li><li>Realtime 和查询客户端是否兼容</li><li>Worker 恢复逻辑是否兼容</li><li>通知 trigger 是否兼容</li><li>退款 trigger 是否兼容</li><li>历史任务是否需要 read-side normalize</li></ul><h2 id="实现真源" tabindex="-1">实现真源 <a class="header-anchor" href="#实现真源" aria-label="Permalink to &quot;实现真源&quot;">​</a></h2><ul><li>Schema：<a href="https://github.com/iloveopt/arti/tree/main/supabase/migrations" target="_blank" rel="noreferrer"><code>arti/supabase/migrations</code></a></li><li>Runtime：<a href="https://github.com/botearn/ARTI_backend/blob/main/shared/arti_shared/queue_tasks.py" target="_blank" rel="noreferrer"><code>ARTI_backend/shared/arti_shared/queue_tasks.py</code></a></li><li>Worker entry：<a href="https://github.com/botearn/ARTI_backend/blob/main/worker/entrypoint.py" target="_blank" rel="noreferrer"><code>ARTI_backend/worker/entrypoint.py</code></a></li></ul>`,29)])])}const k=a(t,[["render",o]]);export{u as __pageData,k as default};
